 1→/**
 2→ * Native Notification Service
 3→ *
 4→ * Uses the Web Notification API (available in Electron renderer).
 5→ * Only fires when the app is in the background — foreground uses Sonner toasts.
 6→ *
 7→ * Sound names are macOS system sound identifiers (kept for API compatibility,
 8→ * but Electron's Web Notification API doesn't support custom sounds):
 9→ * - "Glass" — completion, success
10→ * - "Basso" — error, failure
11→ * - "Ping" — attention needed
12→ */
13→
14→import { capabilities } from "@/platform/capabilities";
15→
16→let permissionGranted = false;
17→
18→/**
19→ * Request notification permission from the OS.
20→ * Safe to call multiple times — short-circuits if already granted.
21→ */
22→export async function initNotifications(): Promise<boolean> {
23→  if (!capabilities.nativeNotifications) return false;
24→
25→  try {
26→    if (!("Notification" in window)) {
27→      permissionGranted = false;
28→      return false;
29→    }
30→
31→    if (Notification.permission === "granted") {
32→      permissionGranted = true;
33→    } else if (Notification.permission !== "denied") {
34→      const result = await Notification.requestPermission();
35→      permissionGranted = result === "granted";
36→    }
37→  } catch (e) {
38→    console.warn("[Notifications] Failed to request permission:", e);
39→    permissionGranted = false;
40→  }
41→
42→  return permissionGranted;
43→}
44→
45→export interface NotificationOptions {
46→  title: string;
47→  body?: string;
48→  sound?: "Glass" | "Basso" | "Ping";
49→}
50→
51→/**
52→ * Send an OS-level notification. No-ops if permission not granted or not in Electron.
53→ */
54→export function sendNotification({ title, body }: NotificationOptions): void {
55→  if (!capabilities.nativeNotifications || !permissionGranted) return;
56→
57→  try {
58→    new Notification(title, { body });
59→  } catch (e) {
60→    console.warn("[Notifications] Failed to send:", e);
61→  }
62→}
63→

1→export {
2→  initNotifications,
3→  sendNotification,
4→  type NotificationOptions,
5→} from "./notificationService";
6→

  1→/**
  2→ * Global Session Notifications
  3→ *
  4→ * Sends OS-level notifications when the app is in the background.
  5→ *
  6→ * Notification triggers:
  7→ * - Agent finished working (working → idle)                → Glass sound
  8→ * - Agent error (→ error with error_category)              → Basso sound
  9→ * - Agent needs input (→ needs_response)                   → Ping sound
 10→ * - Plan ready for review (→ needs_plan_response)          → Ping sound
 11→ * - Setup failed/completed                                 → Basso/Glass sound
 12→ *
 13→ * All transitions are detected by observing the workspace React Query cache,
 14→ * which is kept fresh by the WS subscription. No IPC event listeners needed.
 15→ *
 16→ * When the app is in the foreground, notifications are suppressed —
 17→ * Sonner toasts handle in-app feedback.
 18→ */
 19→
 20→import { useEffect, useRef } from "react";
 21→import { useQueryClient } from "@tanstack/react-query";
 22→import { match } from "ts-pattern";
 23→import { capabilities } from "@/platform/capabilities";
 24→import { sendNotification } from "@/platform/notifications";
 25→import { isWindowFocused } from "@/shared/hooks/useWindowFocus";
 26→import { track } from "@/platform/analytics";
 27→import { unreadActions } from "@/features/session/store/unreadStore";
 28→import { useWorkspaceStore } from "@/features/workspace/store";
 29→import { workspaceLayoutActions } from "@/features/workspace/store/workspaceLayoutStore";
 30→import type { SessionStatus } from "@shared/types/session";
 31→import type { RepoGroup, SetupStatus } from "@shared/types/workspace";
 32→
 33→/**
 34→ * Batches multiple notifications within a short window into a single one.
 35→ * Prevents notification spam when multiple agents finish simultaneously.
 36→ */
 37→const BATCH_WINDOW_MS = 1500;
 38→
 39→/**
 40→ * Check if the user is currently viewing a specific session.
 41→ * True when the workspace is selected AND the active chat tab matches the session.
 42→ */
 43→function checkIsViewingSession(workspaceId: string, sessionId: string): boolean {
 44→  const selectedWorkspaceId = useWorkspaceStore.getState().selectedWorkspaceId;
 45→  if (selectedWorkspaceId !== workspaceId) return false;
 46→
 47→  const layout = workspaceLayoutActions.getLayout(workspaceId);
 48→  // If no persisted active tab, the workspace's current_session_id is shown
 49→  return layout.activeChatTabSessionId === sessionId || !layout.activeChatTabSessionId;
 50→}
 51→
 52→export function useGlobalSessionNotifications() {
 53→  const prevStatusMap = useRef(new Map<string, SessionStatus>());
 54→  const prevSetupStatusMap = useRef(new Map<string, SetupStatus>());
 55→  const finishedBatch = useRef<string[]>([]);
 56→  const batchTimerRef = useRef<ReturnType<typeof setTimeout>>();
 57→
 58→  const queryClient = useQueryClient();
 59→
 60→  useEffect(() => {
 61→    const canNotify = capabilities.nativeNotifications;
 62→
 63→    function flushFinishedBatch() {
 64→      const batch = finishedBatch.current;
 65→      finishedBatch.current = [];
 66→      batchTimerRef.current = undefined;
 67→
 68→      if (batch.length === 0 || isWindowFocused()) return;
 69→
 70→      if (batch.length === 1) {
 71→        sendNotification({
 72→          title: "Agent finished",
 73→          body: `Session ${batch[0].substring(0, 8)} completed`,
 74→          sound: "Glass",
 75→        });
 76→      } else {
 77→        sendNotification({
 78→          title: `${batch.length} agents finished`,
 79→          body: "Multiple sessions completed",
 80→          sound: "Glass",
 81→        });
 82→      }
 83→    }
 84→
 85→    function queueFinished(sessionId: string) {
 86→      finishedBatch.current.push(sessionId);
 87→      if (!batchTimerRef.current) {
 88→        batchTimerRef.current = setTimeout(flushFinishedBatch, BATCH_WINDOW_MS);
 89→      }
 90→    }
 91→
 92→    // Detect session + setup transitions from the workspace query cache.
 93→    // Only watches current_session_id per workspace. Non-current sessions
 94→    // (extra tabs) are handled by ChatArea which tracks workingSessionIds.
 95→    const unsubscribe = queryClient.getQueryCache().subscribe((event) => {
 96→      if (event.type !== "updated" || !event.query.queryKey[0]) return;
 97→
 98→      const key = event.query.queryKey;
 99→      if (key[0] !== "workspaces" || key[1] !== "by-repo") return;
100→
101→      const groups = event.query.state.data as RepoGroup[] | undefined;
102→      if (!groups) return;
103→
104→      for (const group of groups) {
105→        for (const ws of group.workspaces) {
106→          // --- Session status transitions ---
107→          if (ws.current_session_id && ws.session_status) {
108→            const sessionId = ws.current_session_id;
109→            const status = ws.session_status as SessionStatus;
110→            const prevStatus = prevStatusMap.current.get(sessionId);
111→            prevStatusMap.current.set(sessionId, status);
112→
113→            if (prevStatus && prevStatus !== status) {
114→              // Mark session as unread when transitioning out of "working"
115→              // to any terminal state — but only if user is not currently
116→              // viewing that exact session.
117→              if (
118→                prevStatus === "working" &&
119→                (status === "idle" ||
120→                  status === "error" ||
121→                  status === "needs_response" ||
122→                  status === "needs_plan_response")
123→              ) {
124→                const isViewingSession = checkIsViewingSession(ws.id, sessionId);
125→                if (!isViewingSession) {
126→                  unreadActions.markUnread(sessionId);
127→                }
128→              }
129→
130→              // working → idle = agent finished
131→              if (prevStatus === "working" && status === "idle") {
132→                track("ai_turn_completed", { session_id: sessionId });
133→                if (canNotify && !isWindowFocused()) queueFinished(sessionId);
134→              }
135→
136→              // → needs_response = agent needs user input
137→              if (status === "needs_response" && canNotify && !isWindowFocused()) {
138→                sendNotification({
139→                  title: "Agent needs input",
140→                  body: `Session ${sessionId.substring(0, 8)} is waiting for your response`,
141→                  sound: "Ping",
142→                });
143→              }
144→
145→              // → needs_plan_response = plan ready for review
146→              if (status === "needs_plan_response" && canNotify && !isWindowFocused()) {
147→                sendNotification({
148→                  title: "Plan ready for review",
149→                  body: `Session ${sessionId.substring(0, 8)} has a plan waiting for approval`,
150→                  sound: "Ping",
151→                });
152→              }
153→
154→              // → error = agent errored (with category-aware title)
155→              if (status === "error") {
156→                const category = ws.session_error_category ?? undefined;
157→                track("session_error_displayed", {
158→                  session_id: sessionId,
159→                  error_category: category,
160→                });
161→
162→                if (canNotify && !isWindowFocused()) {
163→                  const title = match(category)
164→                    .with("auth", () => "Authentication Error")
165→                    .with("rate_limit", () => "Rate Limited")
166→                    .with("context_limit", () => "Context Limit Reached")
167→                    .with("network", () => "Network Error")
168→                    .with("db_write", () => "Database Error")
169→                    .with("process_exit", () => "Agent Process Crashed")
170→                    .otherwise(() => "Agent Error");
171→                  sendNotification({
172→                    title,
173→                    body:
174→                      ws.session_error_message ||
175→                      `Session ${sessionId.substring(0, 8)} encountered an error`,
176→                    sound: "Basso",
177→                  });
178→                }
179→              }
180→            }
181→          }
182→
183→          // --- Setup status transitions ---
184→          const prevSetup = prevSetupStatusMap.current.get(ws.id);
185→          prevSetupStatusMap.current.set(ws.id, ws.setup_status);
186→
187→          if (!prevSetup) continue;
188→          if (prevSetup === ws.setup_status) continue;
189→
190→          if (
191→            prevSetup === "running" &&
192→            (ws.setup_status === "failed" || ws.setup_status === "completed")
193→          ) {
194→            track("workspace_setup_completed", {
195→              workspace_id: ws.id,
196→              setup_status: ws.setup_status,
197→            });
198→          }
199→
200→          if (
201→            prevSetup === "running" &&
202→            ws.setup_status === "failed" &&
203→            canNotify &&
204→            !isWindowFocused()
205→          ) {
206→            sendNotification({
207→              title: "Setup failed",
208→              body: `Workspace ${ws.title || ws.slug} setup failed${ws.error_message ? `: ${ws.error_message}` : ""}`,
209→              sound: "Basso",
210→            });
211→          }
212→
213→          if (prevSetup === "running" && ws.setup_status === "completed") {
214→            queryClient.invalidateQueries({ queryKey: ["workspaces", "manifest", ws.id] });
215→            if (canNotify && !isWindowFocused()) {
216→              sendNotification({
217→                title: "Setup complete",
218→                body: `Workspace ${ws.title || ws.slug} is ready`,
219→                sound: "Glass",
220→              });
221→            }
222→          }
223→        }
224→      }
225→    });
226→
227→    return () => {
228→      unsubscribe();
229→      if (batchTimerRef.current) clearTimeout(batchTimerRef.current);
230→    };
231→  }, [queryClient]);
232→}
233→

